mapper.select:
SELECT o.order_id AS id, o.order_id AS orderId, o.order_status AS status, IFNULL(oi.price, 0) AS amount, IFNULL(oi.quantity, 1) AS quantity, IFNULL(p.product_category_name, '其他/未分类') AS productCategory, IFNULL(p.product_category_name, '其他/未分类') AS category, IFNULL(p.product_category_name, '未分类商品') AS productName, IFNULL(c.customer_city, '未知城市') AS customerCity, IFNULL(c.customer_city, '未知城市') AS city, o.order_purchase_timestamp AS orderPurchaseTimestamp, DATE(o.order_purchase_timestamp) AS date FROM olist_orders o LEFT JOIN olist_order_items oi ON o.order_id = oi.order_id LEFT JOIN olist_products p ON oi.product_id = p.product_id LEFT JOIN olist_customers c ON o.customer_id = c.customer_id
AND (o.order_id LIKE CONCAT('%', #{keyword}, '%') OR c.customer_city LIKE CONCAT('%', #{keyword}, '%') OR p.product_category_name LIKE CONCAT('%', #{keyword}, '%'))
AND p.product_category_name = #{category}
ORDER BY o.order_purchase_timestamp DESC LIMIT #{offset}, #{size}

SELECT COUNT(DISTINCT o.order_id) FROM olist_orders o LEFT JOIN olist_order_items oi ON o.order_id = oi.order_id LEFT JOIN olist_products p ON oi.product_id = p.product_id LEFT JOIN olist_customers c ON o.customer_id = c.customer_id
AND (o.order_id LIKE CONCAT('%', #{keyword}, '%') OR c.customer_city LIKE CONCAT('%', #{keyword}, '%') OR p.product_category_name LIKE CONCAT('%', #{keyword}, '%'))
AND p.product_category_name = #{category}

SELECT COUNT(DISTINCT o.order_id) AS order_count, COALESCE(SUM(oi.price * oi.quantity), 0) AS amount FROM olist_orders o LEFT JOIN olist_order_items oi ON o.order_id = oi.order_id LEFT JOIN olist_products p ON oi.product_id = p.product_id LEFT JOIN olist_customers c ON o.customer_id = c.customer_id
AND (o.order_id LIKE CONCAT('%', #{keyword}, '%') OR c.customer_city LIKE CONCAT('%', #{keyword}, '%') OR p.product_category_name LIKE CONCAT('%', #{keyword}, '%'))
AND p.product_category_name = #{category}
